SELECT * FROM [hranalytics_db].[dbo].fact_employee_metrics;

SELECT 
    'Attrition Rate' as metrics_name, 
    abs(COUNT(CASE WHEN attrition_flag = 1 THEN 1 END) * 100.0 / COUNT(*)) AS metrics_value
FROM hranalytics_db.dbo.fact_employee_metrics;

SELECT exit_reason as metric_name, COUNT(*) AS metric_value
FROM hranalytics_db.dbo.silver_exit
GROUP BY exit_reason
ORDER BY 1 DESC;


SELECT AVG(survey_score) AS avg_engagement
FROM hranalytics_db.dbo.fact_employee_metrics;

SELECT emp_sk
FROM hranalytics_db.dbo.fact_employee_metrics
WHERE rating < 2 AND survey_score < 5;
